{
  "name": "Italiano Flash: Cultural Vocabulary",
  "description": "A high-performance flashcard application designed to help users master English-to-Italian vocabulary and unique cultural terms from Italian vlogs. Features interactive card flipping, dual-language modes, and AI-powered contextual sentences."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Word {
  id: string;
  en: string;
  it: string;
  category: 'grammar' | 'content' | 'cultural';
  description?: string;
}

export enum LanguageMode {
  EN_TO_IT = 'EN_TO_IT',
  IT_TO_EN = 'IT_TO_EN'
}

export interface FlashcardProps {
  word: Word;
  isFlipped: boolean;
  onFlip: () => void;
  mode: LanguageMode;
}

import React from 'react';
import { FlashcardProps, LanguageMode } from '../types';

const Flashcard: React.FC<FlashcardProps> = ({ word, isFlipped, onFlip, mode }) => {
  const frontText = mode === LanguageMode.EN_TO_IT ? word.en : word.it;
  const backText = mode === LanguageMode.EN_TO_IT ? word.it : word.en;

  const getCategoryColor = () => {
    switch(word.category) {
      case 'grammar': return 'bg-blue-500';
      case 'content': return 'bg-emerald-500';
      case 'cultural': return 'bg-rose-500';
      default: return 'bg-gray-500';
    }
  };

  return (
    <div 
      className="w-full max-w-sm h-80 perspective cursor-pointer group"
      onClick={onFlip}
    >
      <div className={`relative w-full h-full duration-500 preserve-3d shadow-xl rounded-2xl ${isFlipped ? 'rotate-y-180' : ''}`}>

        {/* Front Side */}
        <div className="absolute w-full h-full backface-hidden bg-white rounded-2xl border-4 border-gray-100 flex flex-col items-center justify-center p-8 text-center">
          <div className={`absolute top-4 right-4 text-[10px] uppercase tracking-wider font-bold text-white px-2 py-1 rounded-full ${getCategoryColor()}`}>
            {word.category}
          </div>
          <p className="text-gray-400 text-sm mb-2 uppercase tracking-widest">
            {mode === LanguageMode.EN_TO_IT ? 'English' : 'Italiano'}
          </p>
          <h2 className="text-4xl font-bold text-gray-800 break-words w-full">
            {frontText}
          </h2>
          <p className="mt-8 text-gray-300 text-xs italic">Tap to flip</p>
        </div>

        {/* Back Side */}
        <div className="absolute w-full h-full backface-hidden bg-gray-900 text-white rounded-2xl border-4 border-emerald-400 flex flex-col items-center justify-center p-8 text-center rotate-y-180">
          <p className="text-emerald-400 text-sm mb-2 uppercase tracking-widest">
            {mode === LanguageMode.EN_TO_IT ? 'Italiano' : 'English'}
          </p>
          <h2 className="text-4xl font-bold break-words w-full">
            {backText}
          </h2>
          {word.description && (
            <p className="mt-4 text-gray-400 text-sm leading-relaxed">
              {word.description}
            </p>
          )}
          <div className="absolute bottom-4 text-emerald-300 text-[10px] flex items-center gap-1 opacity-60">
            <i className="fa-solid fa-circle-check"></i>
            <span>Nice Job!</span>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Flashcard;

import React, { useState, useCallback, useEffect, useMemo } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Word, LanguageMode } from './types';
import { VOCABULARY } from './data/words';
import Flashcard from './components/Flashcard';

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [mode, setMode] = useState<LanguageMode>(LanguageMode.EN_TO_IT);
  const [shuffledVocab, setShuffledVocab] = useState<Word[]>([...VOCABULARY]);
  const [aiContext, setAiContext] = useState<string | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Initialize with a shuffle
  useEffect(() => {
    shuffle();
  }, []);

  const currentWord = shuffledVocab[currentIndex];

  const shuffle = () => {
    const shuffled = [...VOCABULARY].sort(() => Math.random() - 0.5);
    setShuffledVocab(shuffled);
    setCurrentIndex(0);
    setIsFlipped(false);
    setAiContext(null);
  };

  const nextCard = useCallback(() => {
    setIsFlipped(false);
    setAiContext(null);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % shuffledVocab.length);
    }, 150);
  }, [shuffledVocab.length]);

  const prevCard = useCallback(() => {
    setIsFlipped(false);
    setAiContext(null);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev - 1 + shuffledVocab.length) % shuffledVocab.length);
    }, 150);
  }, [shuffledVocab.length]);

  const toggleMode = () => {
    setMode((prev) => prev === LanguageMode.EN_TO_IT ? LanguageMode.IT_TO_EN : LanguageMode.EN_TO_IT);
    setIsFlipped(false);
    setAiContext(null);
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const getAiSentence = async () => {
    if (isLoadingAi) return;
    setIsLoadingAi(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a short, natural Italian sentence using the word "${currentWord.it}". 
                   Also provide the English translation. Keep it friendly and relevant to a travel vlog context.`,
        config: {
          systemInstruction: "You are an Italian language tutor. Provide concise examples.",
          temperature: 0.7,
        }
      });
      setAiContext(response.text || "Could not generate example.");
    } catch (err) {
      console.error("AI Error:", err);
      setAiContext("Error fetching AI context. Please check your API key.");
    } finally {
      setIsLoadingAi(false);
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center pb-20 overflow-x-hidden">
      {/* Header */}
      <header className="w-full bg-white border-b border-gray-200 py-4 px-6 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center gap-2">
          <div className="flex">
            <div className="w-2 h-6 bg-emerald-600"></div>
            <div className="w-2 h-6 bg-white border-y border-gray-200"></div>
            <div className="w-2 h-6 bg-red-600"></div>
          </div>
          <h1 className="text-xl font-bold text-gray-800 tracking-tight">Italiano Flash</h1>
        </div>

        <button 
          onClick={toggleMode}
          className="bg-gray-100 hover:bg-gray-200 transition-colors px-4 py-2 rounded-full text-xs font-bold uppercase flex items-center gap-2 text-gray-700"
        >
          <i className="fa-solid fa-right-left"></i>
          {mode === LanguageMode.EN_TO_IT ? 'EN → IT' : 'IT → EN'}
        </button>
      </header>

      {/* Progress Bar */}
      <div className="w-full max-w-md px-6 mt-8">
        <div className="flex justify-between items-end mb-2">
          <span className="text-xs font-bold text-gray-400 uppercase">Current Progress</span>
          <span className="text-sm font-bold text-emerald-600">{currentIndex + 1} / {shuffledVocab.length}</span>
        </div>
        <div className="h-1.5 w-full bg-gray-200 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-300" 
            style={{ width: `${((currentIndex + 1) / shuffledVocab.length) * 100}%` }}
          ></div>
        </div>
      </div>

      {/* Main Flashcard Container */}
      <main className="flex-1 w-full flex flex-col items-center justify-center p-6 mt-4">
        <Flashcard 
          word={currentWord} 
          isFlipped={isFlipped} 
          onFlip={handleFlip} 
          mode={mode} 
        />

        {/* AI Context Section */}
        <div className="mt-8 w-full max-w-sm">
          {aiContext ? (
            <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl animate-slide">
              <h4 className="text-[10px] font-bold text-emerald-600 uppercase mb-2 flex items-center gap-2">
                <i className="fa-solid fa-sparkles"></i> AI Context Example
              </h4>
              <p className="text-gray-800 text-sm leading-relaxed whitespace-pre-line">
                {aiContext}
              </p>
            </div>
          ) : (
            <button 
              onClick={getAiSentence}
              disabled={isLoadingAi}
              className="w-full py-3 bg-white border-2 border-dashed border-gray-300 rounded-xl text-gray-400 text-sm font-medium hover:border-emerald-400 hover:text-emerald-500 transition-all flex items-center justify-center gap-2"
            >
              {isLoadingAi ? (
                <i className="fa-solid fa-spinner animate-spin"></i>
              ) : (
                <i className="fa-solid fa-wand-magic-sparkles"></i>
              )}
              {isLoadingAi ? 'Thinking...' : 'Get AI Example Sentence'}
            </button>
          )}
        </div>
      </main>

      {/* Footer Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 flex items-center justify-center gap-6 shadow-[0_-4px_20px_rgba(0,0,0,0.05)]">
        <button 
          onClick={prevCard}
          className="w-14 h-14 rounded-full bg-gray-100 flex items-center justify-center text-gray-600 hover:bg-gray-200 transition-colors active:scale-95"
          title="Previous Card"
        >
          <i className="fa-solid fa-chevron-left text-xl"></i>
        </button>

        <button 
          onClick={shuffle}
          className="w-14 h-14 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600 hover:bg-emerald-100 transition-colors active:scale-95"
          title="Shuffle Deck"
        >
          <i className="fa-solid fa-shuffle text-xl"></i>
        </button>

        <button 
          onClick={nextCard}
          className="w-14 h-14 rounded-full bg-gray-900 flex items-center justify-center text-white hover:bg-gray-800 transition-colors active:scale-95 shadow-lg shadow-gray-200"
          title="Next Card"
        >
          <i className="fa-solid fa-chevron-right text-xl"></i>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useEffect } from 'react';
import { GoogleGenAI } from '@google/genai';
import { Word, LanguageMode } from './types';
import { VOCABULARY } from './data/words';
import Flashcard from './components/Flashcard';

const App: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [mode, setMode] = useState<LanguageMode>(LanguageMode.EN_TO_IT);
  const [shuffledVocab, setShuffledVocab] = useState<Word[]>([...VOCABULARY]);
  const [aiContext, setAiContext] = useState<string | null>(null);
  const [isLoadingAi, setIsLoadingAi] = useState(false);

  // Performance tracking
  const [masteredIds, setMasteredIds] = useState<Set<string>>(new Set());
  const [learningIds, setLearningIds] = useState<Set<string>>(new Set());

  // Initialize with a shuffle
  useEffect(() => {
    shuffle();
  }, []);

  const currentWord = shuffledVocab[currentIndex];

  const shuffle = () => {
    const shuffled = [...VOCABULARY].sort(() => Math.random() - 0.5);
    setShuffledVocab(shuffled);
    setCurrentIndex(0);
    setIsFlipped(false);
    setAiContext(null);
  };

  const nextCard = useCallback(() => {
    setIsFlipped(false);
    setAiContext(null);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % shuffledVocab.length);
    }, 150);
  }, [shuffledVocab.length]);

  const prevCard = useCallback(() => {
    setIsFlipped(false);
    setAiContext(null);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev - 1 + shuffledVocab.length) % shuffledVocab.length);
    }, 150);
  }, [shuffledVocab.length]);

  const markPerformance = (status: 'mastered' | 'learning') => {
    const wordId = currentWord.id;
    if (status === 'mastered') {
      setMasteredIds(prev => new Set(prev).add(wordId));
      setLearningIds(prev => {
        const next = new Set(prev);
        next.delete(wordId);
        return next;
      });
    } else {
      setLearningIds(prev => new Set(prev).add(wordId));
      setMasteredIds(prev => {
        const next = new Set(prev);
        next.delete(wordId);
        return next;
      });
    }
    // Auto-advance after scoring
    nextCard();
  };

  const toggleMode = () => {
    setMode((prev) => prev === LanguageMode.EN_TO_IT ? LanguageMode.IT_TO_EN : LanguageMode.EN_TO_IT);
    setIsFlipped(false);
    setAiContext(null);
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const getAiSentence = async () => {
    if (isLoadingAi) return;
    setIsLoadingAi(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a short, natural Italian sentence using the word "${currentWord.it}". 
                   Also provide the English translation. Keep it friendly and relevant to a travel vlog context.`,
        config: {
          systemInstruction: "You are an Italian language tutor. Provide concise examples.",
          temperature: 0.7,
        }
      });
      setAiContext(response.text || "Could not generate example.");
    } catch (err) {
      console.error("AI Error:", err);
      setAiContext("Error fetching AI context. Please check your API key.");
    } finally {
      setIsLoadingAi(false);
    }
  };

  const masteryStatus = masteredIds.has(currentWord.id) ? 'mastered' : learningIds.has(currentWord.id) ? 'learning' : null;

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center pb-32 overflow-x-hidden">
      {/* Header */}
      <header className="w-full bg-white border-b border-gray-200 py-4 px-6 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="flex">
            <div className="w-2 h-6 bg-emerald-600"></div>
            <div className="w-2 h-6 bg-white border-y border-gray-200"></div>
            <div className="w-2 h-6 bg-red-600"></div>
          </div>
          <h1 className="text-xl font-bold text-gray-800 tracking-tight">Italiano Flash</h1>
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-2 text-xs font-bold text-gray-400">
            <span className="flex items-center gap-1"><i className="fa-solid fa-check text-emerald-500"></i> {masteredIds.size}</span>
            <span className="flex items-center gap-1"><i className="fa-solid fa-xmark text-rose-500"></i> {learningIds.size}</span>
          </div>
          <button 
            onClick={toggleMode}
            className="bg-gray-100 hover:bg-gray-200 transition-colors px-4 py-2 rounded-full text-xs font-bold uppercase flex items-center gap-2 text-gray-700"
          >
            <i className="fa-solid fa-right-left"></i>
            {mode === LanguageMode.EN_TO_IT ? 'EN → IT' : 'IT → EN'}
          </button>
        </div>
      </header>

      {/* Progress Bar */}
      <div className="w-full max-w-md px-6 mt-8">
        <div className="flex justify-between items-end mb-2">
          <span className="text-xs font-bold text-gray-400 uppercase">Deck Progress</span>
          <span className="text-sm font-bold text-emerald-600">{currentIndex + 1} / {shuffledVocab.length}</span>
        </div>
        <div className="h-1.5 w-full bg-gray-200 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-300" 
            style={{ width: `${((currentIndex + 1) / shuffledVocab.length) * 100}%` }}
          ></div>
        </div>
      </div>

      {/* Main Flashcard Container */}
      <main className="flex-1 w-full flex flex-col items-center justify-center p-6 mt-4">
        <Flashcard 
          word={{
            ...currentWord,
            description: masteryStatus === 'mastered' ? `(Mastered) ${currentWord.description || ''}` : currentWord.description
          }} 
          isFlipped={isFlipped} 
          onFlip={handleFlip} 
          mode={mode} 
        />

        {/* Assessment Buttons - Only show when flipped */}
        <div className={`mt-6 flex gap-4 transition-all duration-300 w-full max-w-sm ${isFlipped ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
          <button 
            onClick={(e) => { e.stopPropagation(); markPerformance('learning'); }}
            className="flex-1 bg-white border-2 border-rose-100 text-rose-600 py-3 rounded-2xl font-bold text-sm hover:bg-rose-50 flex items-center justify-center gap-2 shadow-sm transition-all active:scale-95"
          >
            <i className="fa-solid fa-xmark"></i> Study Again
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); markPerformance('mastered'); }}
            className="flex-1 bg-emerald-500 text-white py-3 rounded-2xl font-bold text-sm hover:bg-emerald-600 flex items-center justify-center gap-2 shadow-lg shadow-emerald-100 transition-all active:scale-95"
          >
            <i className="fa-solid fa-check"></i> I Got It!
          </button>
        </div>

        {/* AI Context Section */}
        <div className="mt-8 w-full max-w-sm">
          {aiContext ? (
            <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl animate-slide">
              <h4 className="text-[10px] font-bold text-emerald-600 uppercase mb-2 flex items-center gap-2">
                <i className="fa-solid fa-sparkles"></i> AI Context Example
              </h4>
              <p className="text-gray-800 text-sm leading-relaxed whitespace-pre-line">
                {aiContext}
              </p>
            </div>
          ) : (
            <button 
              onClick={getAiSentence}
              disabled={isLoadingAi}
              className="w-full py-3 bg-white border-2 border-dashed border-gray-300 rounded-xl text-gray-400 text-sm font-medium hover:border-emerald-400 hover:text-emerald-500 transition-all flex items-center justify-center gap-2"
            >
              {isLoadingAi ? (
                <i className="fa-solid fa-spinner animate-spin"></i>
              ) : (
                <i className="fa-solid fa-wand-magic-sparkles"></i>
              )}
              {isLoadingAi ? 'Thinking...' : 'Get AI Example Sentence'}
            </button>
          )}
        </div>
      </main>

      {/* Footer Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 pb-8 flex items-center justify-center gap-6 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] z-40">
        <button 
          onClick={prevCard}
          className="w-14 h-14 rounded-full bg-gray-100 flex items-center justify-center text-gray-600 hover:bg-gray-200 transition-colors active:scale-95"
          title="Previous Card"
        >
          <i className="fa-solid fa-chevron-left text-xl"></i>
        </button>

        <button 
          onClick={shuffle}
          className="w-14 h-14 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600 hover:bg-emerald-100 transition-colors active:scale-95"
          title="Shuffle Deck"
        >
          <i className="fa-solid fa-shuffle text-xl"></i>
        </button>

        <button 
          onClick={nextCard}
          className="w-14 h-14 rounded-full bg-gray-900 flex items-center justify-center text-white hover:bg-gray-800 transition-colors active:scale-95 shadow-lg shadow-gray-200"
          title="Next Card"
        >
          <i className="fa-solid fa-chevron-right text-xl"></i>
        </button>
      </nav>
    </div>
  );
};

export default App;

import React from 'react';
import { FlashcardProps, LanguageMode } from '../types';

const Flashcard: React.FC<FlashcardProps> = ({ word, isFlipped, onFlip, mode }) => {
  const frontText = mode === LanguageMode.EN_TO_IT ? word.en : word.it;
  const backText = mode === LanguageMode.EN_TO_IT ? word.it : word.en;

  const getCategoryColor = () => {
    switch(word.category) {
      case 'grammar': return 'bg-blue-500';
      case 'content': return 'bg-emerald-500';
      case 'cultural': return 'bg-rose-500';
      default: return 'bg-gray-500';
    }
  };

  const isMastered = word.description?.startsWith('(Mastered)');
  const cleanDescription = word.description?.replace('(Mastered) ', '');

  return (
    <div 
      className="w-full max-w-sm h-80 perspective cursor-pointer group"
      onClick={onFlip}
    >
      <div className={`relative w-full h-full duration-500 preserve-3d shadow-xl rounded-2xl ${isFlipped ? 'rotate-y-180' : ''}`}>

        {/* Front Side */}
        <div className="absolute w-full h-full backface-hidden bg-white rounded-2xl border-4 border-gray-100 flex flex-col items-center justify-center p-8 text-center overflow-hidden">
          <div className={`absolute top-4 right-4 text-[10px] uppercase tracking-wider font-bold text-white px-2 py-1 rounded-full ${getCategoryColor()} z-10`}>
            {word.category}
          </div>

          {isMastered && (
            <div className="absolute top-0 left-0 bg-emerald-500 text-white p-1 pr-3 rounded-br-2xl flex items-center gap-1">
              <i className="fa-solid fa-circle-check text-xs ml-1"></i>
              <span className="text-[10px] font-bold uppercase tracking-tight">Mastered</span>
            </div>
          )}

          <p className="text-gray-400 text-sm mb-2 uppercase tracking-widest">
            {mode === LanguageMode.EN_TO_IT ? 'English' : 'Italiano'}
          </p>
          <h2 className="text-4xl font-bold text-gray-800 break-words w-full px-2">
            {frontText}
          </h2>
          <p className="mt-8 text-gray-300 text-xs italic">Tap to flip</p>
        </div>

        {/* Back Side */}
        <div className="absolute w-full h-full backface-hidden bg-gray-900 text-white rounded-2xl border-4 border-emerald-400 flex flex-col items-center justify-center p-8 text-center rotate-y-180 overflow-hidden">
          <p className="text-emerald-400 text-sm mb-2 uppercase tracking-widest">
            {mode === LanguageMode.EN_TO_IT ? 'Italiano' : 'English'}
          </p>
          <h2 className="text-4xl font-bold break-words w-full px-2">
            {backText}
          </h2>
          {cleanDescription && (
            <p className="mt-4 text-gray-400 text-sm leading-relaxed italic">
              {cleanDescription}
            </p>
          )}
          <div className="absolute bottom-4 text-emerald-300 text-[10px] flex items-center gap-1 opacity-60">
            <i className="fa-solid fa-lightbulb"></i>
            <span>Check your knowledge</span>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Flashcard;

