  };

  const nextCard = useCallback(() => {
    setIsFlipped(false);
    setAiContext(null);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % shuffledVocab.length);
    }, 150);
  }, [shuffledVocab.length]);

  const prevCard = useCallback(() => {
    setIsFlipped(false);
    setAiContext(null);
    setTimeout(() => {
      setCurrentIndex((prev) => (prev - 1 + shuffledVocab.length) % shuffledVocab.length);
    }, 150);
  }, [shuffledVocab.length]);

  const markPerformance = (status: 'mastered' | 'learning') => {
    const wordId = currentWord.id;

    if (status === 'mastered') {
      setMasteredIds(prev => new Set(prev).add(wordId));
      setLearningIds(prev => {
        const next = new Set(prev);
        next.delete(wordId);
        return next;
      });
      nextCard();
    } else {
      setLearningIds(prev => new Set(prev).add(wordId));
      setMasteredIds(prev => {
        const next = new Set(prev);
        next.delete(wordId);
        return next;
      });

      // Special logic: Put the missed card back into the deck 3-5 positions later
      const newVocab = [...shuffledVocab];
      const missedCard = newVocab.splice(currentIndex, 1)[0];
      const reinsertIndex = Math.min(currentIndex + 3, newVocab.length);
      newVocab.splice(reinsertIndex, 0, missedCard);

      setShuffledVocab(newVocab);
      // We don't advance currentIndex because we just removed the card from this spot
      // and another card shifted into it.
      setIsFlipped(false);
      setAiContext(null);
    }
  };

  const toggleMode = () => {
    setMode((prev) => prev === LanguageMode.EN_TO_IT ? LanguageMode.IT_TO_EN : LanguageMode.EN_TO_IT);
    setIsFlipped(false);
    setAiContext(null);
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const getAiSentence = async () => {
    if (isLoadingAi) return;
    setIsLoadingAi(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Generate a short, natural Italian sentence using the word "${currentWord.it}". 
                   Also provide the English translation. Keep it friendly and relevant to a travel vlog context.`,
        config: {
          systemInstruction: "You are an Italian language tutor. Provide concise examples.",
          temperature: 0.7,
        }
      });
      setAiContext(response.text || "Could not generate example.");
    } catch (err) {
      console.error("AI Error:", err);
      setAiContext("Error fetching AI context. Please check your API key.");
    } finally {
      setIsLoadingAi(false);
    }
  };

  const masteryStatus = masteredIds.has(currentWord.id) ? 'mastered' : learningIds.has(currentWord.id) ? 'learning' : null;

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center pb-32 overflow-x-hidden">
      {/* Header */}
      <header className="w-full bg-white border-b border-gray-200 py-4 px-6 flex items-center justify-between sticky top-0 z-50 shadow-sm">
        <div className="flex items-center gap-2">
          <div className="flex">
            <div className="w-2 h-6 bg-emerald-600"></div>
            <div className="w-2 h-6 bg-white border-y border-gray-200"></div>
            <div className="w-2 h-6 bg-red-600"></div>
          </div>
          <h1 className="text-xl font-bold text-gray-800 tracking-tight">Italiano Flash</h1>
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-4 text-xs font-bold">
            <div className="flex flex-col items-center">
              <span className="text-emerald-500">{masteredIds.size}</span>
              <span className="text-[8px] text-gray-400 uppercase">Mastered</span>
            </div>
            <div className="flex flex-col items-center">
              <span className="text-rose-500">{learningIds.size}</span>
              <span className="text-[8px] text-gray-400 uppercase">To Review</span>
            </div>
          </div>
          <button 
            onClick={toggleMode}
            className="bg-gray-100 hover:bg-gray-200 transition-colors px-4 py-2 rounded-full text-xs font-bold uppercase flex items-center gap-2 text-gray-700"
          >
            <i className="fa-solid fa-right-left"></i>
            {mode === LanguageMode.EN_TO_IT ? 'EN → IT' : 'IT → EN'}
          </button>
        </div>
      </header>

      {/* Progress Bar */}
      <div className="w-full max-w-md px-6 mt-8">
        <div className="flex justify-between items-end mb-2">
          <span className="text-xs font-bold text-gray-400 uppercase">Session Progress</span>
          <span className="text-sm font-bold text-emerald-600">{currentIndex + 1} / {shuffledVocab.length}</span>
        </div>
        <div className="h-1.5 w-full bg-gray-200 rounded-full overflow-hidden">
          <div 
            className="h-full bg-emerald-500 transition-all duration-300" 
            style={{ width: `${((currentIndex + 1) / shuffledVocab.length) * 100}%` }}
          ></div>
        </div>
      </div>

      {/* Main Flashcard Container */}
      <main className="flex-1 w-full flex flex-col items-center justify-center p-6 mt-4">
        <Flashcard 
          word={{
            ...currentWord,
            description: masteryStatus === 'mastered' ? `(Mastered) ${currentWord.description || ''}` : currentWord.description
          }} 
          isFlipped={isFlipped} 
          onFlip={handleFlip} 
          mode={mode} 
        />

        {/* Assessment Buttons - Now with Thumbs icons */}
        <div className={`mt-6 flex gap-4 transition-all duration-300 w-full max-w-sm ${isFlipped ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
          <button 
            onClick={(e) => { e.stopPropagation(); markPerformance('learning'); }}
            className="flex-1 bg-white border-2 border-rose-200 text-rose-600 py-4 rounded-2xl font-bold text-sm hover:bg-rose-50 flex flex-col items-center justify-center gap-1 shadow-sm transition-all active:scale-95 group"
          >
            <i className="fa-solid fa-thumbs-down text-xl group-hover:-rotate-12 transition-transform"></i>
            <span>Hard</span>
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); markPerformance('mastered'); }}
            className="flex-1 bg-emerald-500 text-white py-4 rounded-2xl font-bold text-sm hover:bg-emerald-600 flex flex-col items-center justify-center gap-1 shadow-lg shadow-emerald-100 transition-all active:scale-95 group"
          >
            <i className="fa-solid fa-thumbs-up text-xl group-hover:rotate-12 transition-transform"></i>
            <span>Easy!</span>
          </button>
        </div>

        {/* AI Context Section */}
        <div className="mt-8 w-full max-w-sm">
          {aiContext ? (
            <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl animate-slide relative">
              <button 
                onClick={() => setAiContext(null)}
                className="absolute top-2 right-2 text-gray-400 hover:text-gray-600"
              >
                <i className="fa-solid fa-xmark text-xs"></i>
              </button>
              <h4 className="text-[10px] font-bold text-emerald-600 uppercase mb-2 flex items-center gap-2">
                <i className="fa-solid fa-sparkles"></i> AI Context Example
              </h4>
              <p className="text-gray-800 text-sm leading-relaxed whitespace-pre-line">
                {aiContext}
              </p>
            </div>
          ) : (
            <button 
              onClick={getAiSentence}
              disabled={isLoadingAi}
              className="w-full py-3 bg-white border-2 border-dashed border-gray-300 rounded-xl text-gray-400 text-sm font-medium hover:border-emerald-400 hover:text-emerald-500 transition-all flex items-center justify-center gap-2"
            >
              {isLoadingAi ? (
                <i className="fa-solid fa-spinner animate-spin"></i>
              ) : (
                <i className="fa-solid fa-wand-magic-sparkles"></i>
              )}
              {isLoadingAi ? 'Thinking...' : 'Get AI Example Sentence'}
            </button>
          )}
        </div>
      </main>

      {/* Footer Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 p-4 pb-8 flex items-center justify-center gap-6 shadow-[0_-4px_20px_rgba(0,0,0,0.05)] z-40">
        <button 
          onClick={prevCard}
