        <button 
          onClick={shuffle}
          className="w-14 h-14 rounded-full bg-emerald-50 flex items-center justify-center text-emerald-600 hover:bg-emerald-100 transition-colors active:scale-95 border-2 border-emerald-100"
          title="Shuffle Deck"
        >
          <i className="fa-solid fa-shuffle text-xl"></i>
        </button>

        <button 
          onClick={nextCard}
          className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center text-gray-400 hover:bg-gray-200 transition-colors active:scale-95"
          title="Skip Card"
        >
          <i className="fa-solid fa-chevron-right"></i>
        </button>
      </nav>
    </div>
  );
};

